-- Create a stored procedure (PostgreSQL)
CREATE OR REPLACE PROCEDURE transfer_funds(
    p_from_account INT,
    p_to_account INT,
    p_amount DECIMAL
)
LANGUAGE plpgsql
AS $$
DECLARE
    v_balance DECIMAL;
BEGIN
    -- Check sufficient balance
    SELECT balance INTO v_balance
    FROM accounts WHERE id = p_from_account FOR UPDATE;

    IF v_balance < p_amount THEN
        RAISE EXCEPTION 'Insufficient funds: % available', v_balance;
    END IF;

    -- Perform transfer atomically
    UPDATE accounts SET balance = balance - p_amount WHERE id = p_from_account;
    UPDATE accounts SET balance = balance + p_amount WHERE id = p_to_account;

    -- Log the transaction
    INSERT INTO transaction_log(from_id, to_id, amount, ts)
    VALUES (p_from_account, p_to_account, p_amount, NOW());

    COMMIT;
END;
$$;

-- Call it
CALL transfer_funds(101, 202, 500.00);

-- Hash sharding (application-level routing)
import hashlib

def get_shard(user_id: int, num_shards: int = 4) -> int:
    return user_id % num_shards
    # user_id=42 -> shard 2
    # user_id=43 -> shard 3

# Each shard is a separate database connection
shards = [
    connect('shard-0.db.internal'),
    connect('shard-1.db.internal'),
    connect('shard-2.db.internal'),
    connect('shard-3.db.internal'),
]

def get_user(user_id: int):
    shard = shards[get_shard(user_id)]
    return shard.execute('SELECT * FROM users WHERE id = ?', user_id)

