-- Table: sales(month, product, revenue)
-- Goal: one column per product, rows per month

-- Standard approach: conditional aggregation (works everywhere)
SELECT
    month,
    SUM(CASE WHEN product = 'Phone'  THEN revenue ELSE 0 END) AS Phone,
    SUM(CASE WHEN product = 'Laptop' THEN revenue ELSE 0 END) AS Laptop,
    SUM(CASE WHEN product = 'Tablet' THEN revenue ELSE 0 END) AS Tablet
FROM sales
GROUP BY month
ORDER BY month;

-- SQL Server native PIVOT
SELECT month, [Phone], [Laptop], [Tablet]
FROM sales
PIVOT (
    SUM(revenue)
    FOR product IN ([Phone], [Laptop], [Tablet])
) AS pivoted;

-- Dynamic pivot in MySQL (when products are unknown at query time)
SET @sql = NULL;
SELECT GROUP_CONCAT(
    DISTINCT CONCAT('SUM(CASE WHEN product = ''', product, ''' THEN revenue ELSE 0 END) AS ', product)
) INTO @sql FROM sales;

SET @sql = CONCAT('SELECT month, ', @sql, ' FROM sales GROUP BY month');
PREPARE stmt FROM @sql;
EXECUTE stmt;

-- Method 1: CREATE TABLE AS SELECT WHERE 1=0
-- Copies column names and types, but NOT constraints or indexes
CREATE TABLE employees_backup AS
SELECT * FROM employees WHERE 1=0;
-- Result: empty table with same columns

-- Method 2: MySQL LIKE syntax (copies constraints too)
CREATE TABLE employees_staging LIKE employees;
-- Copies: columns, data types, indexes, NOT NULL, DEFAULT values
-- Does NOT copy: foreign key constraints

