CREATE TABLE employees_temp (LIKE employees INCLUDING ALL);
-- INCLUDING ALL: copies indexes, constraints, defaults, comments
-- Options: INCLUDING DEFAULTS, INCLUDING CONSTRAINTS, INCLUDING INDEXES

