-- SQL Server: multi-statement TVF with procedural logic
CREATE FUNCTION dbo.GetTopEarners(@n INT)
RETURNS @result TABLE (name VARCHAR(100), salary DECIMAL)
AS BEGIN
    INSERT INTO @result
    SELECT TOP (@n) name, salary FROM employees ORDER BY salary DESC;
    RETURN;
END;

-- MySQL InnoDB: PRIMARY KEY = clustered index (automatic)
CREATE TABLE employees (
    id INT PRIMARY KEY,       -- this IS the clustered index
    name VARCHAR(100),
    department VARCHAR(50),
    salary DECIMAL(10,2)
);

-- Non-clustered index on department (separate B-Tree structure)
CREATE INDEX idx_department ON employees(department);
-- Leaf nodes store: (department value, id) — id is the clustered key pointer

-- Covering index: include extra columns in non-clustered index
-- Avoids going back to the clustered index (table) to fetch the data
CREATE INDEX idx_dept_salary ON employees(department, salary);
-- Query below can be satisfied entirely from the index (Index Only Scan)
SELECT department, AVG(salary) FROM employees GROUP BY department;

-- SQL Server: explicit clustered index (not necessarily on PK)
CREATE CLUSTERED INDEX idx_orders_date ON orders(created_at);
-- Rows are now physically sorted by created_at — great for date-range queries

-- EXPLAIN: see if query uses clustered (Index Scan) or non-clustered (Index Scan + heap fetch)
EXPLAIN SELECT * FROM employees WHERE department = 'Engineering';

-- Basic cursor example (SQL Server)
DECLARE @emp_id INT, @salary DECIMAL;

DECLARE salary_cursor CURSOR FOR
    SELECT id, salary FROM employees WHERE department = 'Sales';

OPEN salary_cursor;

FETCH NEXT FROM salary_cursor INTO @emp_id, @salary;

WHILE @@FETCH_STATUS = 0
BEGIN
    -- Row-by-row logic: apply custom bonus rule
    IF @salary < 50000
        UPDATE employees SET bonus = @salary * 0.15 WHERE id = @emp_id;
    ELSE
        UPDATE employees SET bonus = @salary * 0.10 WHERE id = @emp_id;

    FETCH NEXT FROM salary_cursor INTO @emp_id, @salary;
END;

CLOSE salary_cursor;
DEALLOCATE salary_cursor;

-- BETTER: replace cursor with set-based UPDATE using CASE
UPDATE employees
SET bonus = CASE
    WHEN salary < 50000 THEN salary * 0.15
    ELSE salary * 0.10
END
WHERE department = 'Sales';
-- One SQL statement vs N round trips — dramatically faster

-- VIOLATION of 1NF: multi-valued column
-- BAD: orders(id, customer, items)
-- items: 'Laptop,Mouse,Keyboard'  <- not atomic!

-- 1NF FIX: separate table
CREATE TABLE order_items (order_id INT, item VARCHAR(100));

-- VIOLATION of 2NF: partial dependency on composite key
-- BAD: enrollment(student_id, course_id, student_name, course_title)
-- student_name depends only on student_id (partial dependency!)

-- 2NF FIX: split into separate tables
CREATE TABLE students (student_id INT PRIMARY KEY, student_name VARCHAR(100));
CREATE TABLE courses  (course_id INT PRIMARY KEY, course_title VARCHAR(100));
CREATE TABLE enrollment (student_id INT, course_id INT, grade CHAR(2),
    PRIMARY KEY (student_id, course_id));

-- VIOLATION of 3NF: transitive dependency
-- BAD: employees(id, dept_id, dept_name, dept_location)
-- dept_name and dept_location depend on dept_id, not on employee id

-- 3NF FIX: extract department
CREATE TABLE departments (dept_id INT PRIMARY KEY, dept_name VARCHAR(100), location VARCHAR(100));
CREATE TABLE employees (id INT PRIMARY KEY, name VARCHAR(100), dept_id INT
    REFERENCES departments(dept_id));

-- Covering index: include all queried columns
-- Query: get name and email for active users ordered by name
CREATE INDEX idx_covering ON users(status, name, email);
-- All three columns are in the index — index-only scan, no heap access
SELECT name, email FROM users WHERE status = 'active' ORDER BY name;

-- PostgreSQL INCLUDE (non-key columns in leaf only)
CREATE INDEX idx_user_status ON users(status) INCLUDE (name, email);
-- status is the key; name, email stored at leaf for covering

-- Expression index: index on LOWER(email)
CREATE INDEX idx_lower_email ON users(LOWER(email));
-- Now this uses the index:
SELECT * FROM users WHERE LOWER(email) = 'raj@example.com';

-- Partial index: index only a subset of rows
CREATE INDEX idx_active_users ON users(email) WHERE status = 'active';
-- Smaller index, faster for active-user-only queries

-- Bank transfer: debit account A, credit account B
BEGIN;  -- start transaction

UPDATE accounts SET balance = balance - 1000 WHERE account_id = 'A';
UPDATE accounts SET balance = balance + 1000 WHERE account_id = 'B';

-- If any statement fails:
ROLLBACK;  -- both changes reversed (Atomicity)

-- If all succeed:
COMMIT;    -- both changes persist (Durability)

-- Consistency example: CHECK constraint
ALTER TABLE accounts ADD CONSTRAINT chk_positive_balance CHECK (balance >= 0);
-- If transfer would make balance negative, transaction is rejected

-- Isolation: concurrent reads/writes handled by isolation level
SET TRANSACTION ISOLATION LEVEL SERIALIZABLE;
BEGIN;
SELECT balance FROM accounts WHERE account_id = 'A';  -- sees snapshot
UPDATE accounts SET balance = balance - 500 WHERE account_id = 'A';
COMMIT;

-- MVCC in action (PostgreSQL conceptual)
-- Initial: accounts row { id:1, balance:1000, xmin:10, xmax:null }

-- Transaction T1 (id=20) starts: reads snapshot as of txn 20
-- SELECT balance FROM accounts WHERE id=1 → sees version with xmin<=20 and xmax=null → 1000

-- Transaction T2 (id=21) updates:
-- UPDATE accounts SET balance=500 WHERE id=1
-- Creates new row: { id:1, balance:500, xmin:21, xmax:null }
-- Marks old row: { id:1, balance:1000, xmin:10, xmax:21 }
-- T2 commits

-- T1 still sees: { balance:1000, xmin:10, xmax:21 }
-- Because xmax=21 > T1's snapshot txn_id=20 — old version still visible to T1

-- After T1 commits, old version eligible for VACUUM cleanup
-- In PostgreSQL, run VACUUM to reclaim dead tuples:
-- VACUUM accounts;
-- Or auto-vacuum does this in background

-- DELETE: selective, logged, with WHERE
DELETE FROM orders WHERE status = 'cancelled' AND created_at < '2023-01-01';
-- Can rollback:
BEGIN;
DELETE FROM temp_data;
ROLLBACK;  -- data restored

-- TRUNCATE: fast, all rows, resets sequences
TRUNCATE TABLE session_logs;           -- all rows gone instantly
TRUNCATE TABLE orders RESTART IDENTITY CASCADE;  -- reset serial + cascade to FK tables
-- In PostgreSQL, TRUNCATE is transactional:
BEGIN;
TRUNCATE TABLE staging_data;
ROLLBACK;  -- data restored (PostgreSQL only)

-- DROP: removes the table entirely
DROP TABLE IF EXISTS temp_staging;
-- Cannot rollback in MySQL/Oracle; can rollback in PostgreSQL within txn

-- Performance comparison on 10M rows:
