-- Audit trigger: log every salary change
CREATE TABLE salary_audit (
  id SERIAL PRIMARY KEY,
  employee_id INT,
  old_salary NUMERIC,
  new_salary NUMERIC,
  changed_by TEXT DEFAULT CURRENT_USER,
  changed_at TIMESTAMP DEFAULT NOW()
);

CREATE OR REPLACE FUNCTION log_salary_change()
RETURNS TRIGGER
LANGUAGE plpgsql AS $$
BEGIN
  IF OLD.salary <> NEW.salary THEN
    INSERT INTO salary_audit(employee_id, old_salary, new_salary)
    VALUES (NEW.id, OLD.salary, NEW.salary);
  END IF;
  RETURN NEW;
END;
$$;

CREATE TRIGGER salary_change_trigger
AFTER UPDATE OF salary ON employees
FOR EACH ROW
EXECUTE FUNCTION log_salary_change();

-- BEFORE trigger: validate data before insert
CREATE OR REPLACE FUNCTION validate_order()
RETURNS TRIGGER AS $$
BEGIN
  IF NEW.amount <= 0 THEN
    RAISE EXCEPTION 'Order amount must be positive';
  END IF;
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER validate_order_trigger
BEFORE INSERT ON orders FOR EACH ROW
EXECUTE FUNCTION validate_order();

-- Non-correlated: runs once
SELECT * FROM employees
WHERE department_id IN (
  SELECT id FROM departments WHERE location = 'Bangalore'  -- runs ONCE
);

-- Equivalent JOIN (often faster)
SELECT e.* FROM employees e
JOIN departments d ON e.department_id = d.id
WHERE d.location = 'Bangalore';

-- Correlated: references outer query, runs once per row
SELECT e.name, e.salary
FROM employees e
WHERE e.salary > (
  SELECT AVG(salary) FROM employees   -- runs for EACH employee row
  WHERE department_id = e.department_id  -- references outer 'e'
);
-- Finds employees earning above their department's average

-- Rewrite as window function (much faster)
SELECT name, salary
FROM (
  SELECT name, salary,
         AVG(salary) OVER (PARTITION BY department_id) AS dept_avg
  FROM employees
) t
WHERE salary > dept_avg;

-- EXISTS with correlated subquery
SELECT u.name FROM users u
WHERE EXISTS (
  SELECT 1 FROM orders o WHERE o.user_id = u.id AND o.amount > 1000
);

-- Basic foreign key
CREATE TABLE customers (
  id SERIAL PRIMARY KEY,
  name VARCHAR(100)
);

CREATE TABLE orders (
  id SERIAL PRIMARY KEY,
  customer_id INT NOT NULL,
  amount NUMERIC,
  FOREIGN KEY (customer_id) REFERENCES customers(id)  -- RESTRICT by default
);

-- ON DELETE CASCADE: delete orders when customer deleted
CREATE TABLE orders (
  id SERIAL PRIMARY KEY,
  customer_id INT NOT NULL REFERENCES customers(id) ON DELETE CASCADE
);

-- ON DELETE SET NULL: keep orders, set customer_id to null
CREATE TABLE orders (
  id SERIAL PRIMARY KEY,
  customer_id INT REFERENCES customers(id) ON DELETE SET NULL  -- must be nullable
);

-- Check FK violation
