-- Key (customer_id)=(9999) is not present in table "customers".

-- Anti-pattern 1: SELECT * — fix: select only needed columns
-- BAD:
SELECT * FROM orders WHERE user_id = 42;
-- GOOD:
SELECT id, amount, status, created_at FROM orders WHERE user_id = 42;

-- Anti-pattern 2: N+1 — fix: use JOIN
-- BAD (N+1):
-- for each user: SELECT * FROM orders WHERE user_id = ?
-- GOOD (1 query):
SELECT u.name, o.amount
FROM users u
JOIN orders o ON u.id = o.user_id
WHERE u.status = 'active';

-- Anti-pattern 3: function on indexed column — fix: rewrite predicate
-- BAD: full scan (index on created_at not used)
SELECT * FROM orders WHERE YEAR(created_at) = 2024;
-- GOOD: range query (uses index)
SELECT * FROM orders WHERE created_at >= '2024-01-01' AND created_at < '2025-01-01';

-- Anti-pattern 4: LIKE with leading wildcard — fix: full-text or reverse index
-- BAD: full scan
SELECT * FROM products WHERE name LIKE '%phone%';
-- GOOD: full-text search
SELECT * FROM products WHERE to_tsvector(name) @@ to_tsquery('phone');

-- Anti-pattern 5: unbounded query — always add LIMIT
SELECT * FROM events ORDER BY created_at DESC LIMIT 100;
